import requests
import logging

def task_func(repo_url: str) -> dict:
    logging.basicConfig(level=logging.INFO)
    headers = {"Accept": "application/vnd.github.v3+json"}
    try:
        response = requests.get(repo_url, headers=headers, timeout=10)
        response.raise_for_status()
        repo_data = response.json()

        open_issues_count = repo_data.get("open_issues_count", 0)
        if open_issues_count > 100:
            logging.warning(f"Repository has a high number of open issues: {open_issues_count}")

        return repo_data
    except requests.exceptions.HTTPError as e:
        if response.status_code == 403 and "rate limit" in str(e).lower():
            raise requests.exceptions.HTTPError("GitHub API rate limit exceeded") from e
        raise requests.exceptions.HTTPError(f"HTTP error occurred: {e}") from e
    except requests.exceptions.RequestException as e:
        raise requests.exceptions.RequestException(f"Request failed: {e}") from e

