import socket
import select
import queue
from datetime import datetime, timedelta

def task_func(
    server_address="localhost", server_port=12345, buffer_size=1024, run_duration=5
):
    server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    server_socket.bind((server_address, server_port))
    server_socket.listen(5)
    server_socket.setblocking(False)

    inputs = [server_socket]
    outputs = []
    message_queues = {}

    start_time = datetime.now()
    end_time = start_time + timedelta(seconds=run_duration)

    status_message = f"Server started at {start_time.strftime('%Y-%m-%d %H:%M:%S')} and will run for {run_duration} seconds."

    try:
        while datetime.now() < end_time:
            readable, writable, exceptional = select.select(inputs, outputs, inputs, 1.0)

            for s in exceptional:
                if s in message_queues:
                    del message_queues[s]
                if s in inputs:
                    inputs.remove(s)
                if s in outputs:
                    outputs.remove(s)
                s.close()

            for s in readable:
                if s is server_socket:
                    client_socket, client_address = s.accept()
                    client_socket.setblocking(False)
                    inputs.append(client_socket)
                    message_queues[client_socket] = queue.Queue()
                else:
                    try:
                        data = s.recv(buffer_size)
                        if data:
                            timestamp = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                            response = f"{data.decode('utf-8').strip()} | Server time: {timestamp}\n"
                            message_queues[s].put(response.encode('utf-8'))
                            if s not in outputs:
                                outputs.append(s)
                        else:
                            if s in outputs:
                                outputs.remove(s)
                            inputs.remove(s)
                            del message_queues[s]
                            s.close()
                    except ConnectionResetError:
                        if s in outputs:
                            outputs.remove(s)
                        if s in inputs:
                            inputs.remove(s)
                        del message_queues[s]
                        s.close()

            for s in writable:
                try:
                    if not message_queues[s].empty():
                        next_msg = message_queues[s].get_nowait()
                        s.send(next_msg)
                    else:
                        outputs.remove(s)
                except:
                    outputs.remove(s)
                    del message_queues[s]
                    s.close()

    except Exception as e:
        status_message = f"Server error: {e}"

    finally:
        server_socket.close()
        elapsed = (datetime.now() - start_time).total_seconds()
        status_message = f"Server stopped after {elapsed:.2f} seconds. Total run duration: {run_duration} seconds."

    return status_message

