            elif dtype == tuple:
                length = np.random.randint(1, 6)
                value = tuple(np.random.randint(0, 10) for _ in range(length))
            elif dtype == dict:
                length = np.random.randint(1, 6)
                value = {np.random.randint(0, 10): np.random.randint(0, 10) for _ in range(length)}
            elif dtype == set:
                length = np.random.randint(1, 6)
                value = set(np.random.randint(0, 10) for _ in range(length))
            column_data.append(value)
        data[col_name] = column_data
    return pd.DataFrame(data)

def differ_at_one_bit(a, b):
