        else:
            current_diff -= 1
        max_diff = max(max_diff, current_diff)
        if current_diff < 0:
            current_diff = 0
    return max_diff

def sum_of_common_divisors(a, b):
    def gcd(x, y):
        while y:
            x, y = y, x % y
        return x
    g = gcd(a, b)
    total = 0
    for i in range(1, g + 1):
        if g % i == 0:
            total += i
    return total

def is_magic_square(matrix):
    if not matrix or not all(len(row) == len(matrix) for row in matrix):
        return False
    n = len(matrix)
    target_sum = n * (n * n + 1) // 2
    for row in matrix:
        if sum(row) != target_sum:
            return False
    for col in range(n):
        if sum(matrix[row][col] for row in range(n)) != target_sum:
            return False
    if sum(matrix[i][i] for i in range(n)) != target_sum:
        return False
    if sum(matrix[i][n - 1 - i] for i in range(n)) != target_sum:
        return False
    return True

def max_difference(arr):
