    min_val = arr[0]
    max_diff = 0
    for i in range(1, len(arr)):
        if arr[i] < min_val:
            min_val = arr[i]
        elif arr[i] - min_val > max_diff:
            max_diff = arr[i] - min_val
    return max_diff

def extended_gcd(a, b):
    if a == 0:
        return b, 0, 1
    gcd, x1, y1 = extended_gcd(b % a, a)
    x = y1 - (b // a) * x1
    y = x1
    return gcd, x, y

def solve_linear_diophantine(a, b, n):
    gcd, x0, y0 = extended_gcd(a, b)
    if n % gcd != 0:
        return None
    x = x0 * (n // gcd)
    y = y0 * (n // gcd)
    return (x, y)

def sum_sequence(n):
