def f(n, memo={}):
    if n in memo:
        return memo[n]
    if n == 0:
        return 0
    result = max(f(n//2, memo) + f(n//3, memo) + f(n//4, memo) + f(n//5, memo), n)
    memo[n] = result
    return result

