    if n == 1:
        return 1
    if n == 2:
        return 2
    a, b, c = 3, 0, 2
    total = a + b + c
    for i in range(3, n + 1):
        next_perrin = a + b
        total += next_perrin
        a, b, c = b, c, next_perrin
    return total

def sum_of_even_factors(n):
    if n % 2 != 0:
        return 0
    total = 0
    i = 2
    while i * i <= n:
        if n % i == 0:
            if i % 2 == 0:
                total += i
            if i != n // i and (n // i) % 2 == 0:
                total += n // i
        i += 1
    if n % 2 == 0:
        total += n
    return total

