def lucid_numbers(n):
    def is_lucid(num):
        if num < 1:
            return False
        factors = set()
        d = 2
        while d * d <= num:
            while num % d == 0:
                factors.add(d)
                num //= d
            d += 1
        if num > 1:
            factors.add(num)
        return len(factors) == 2
    return [i for i in range(1, n + 1) if is_lucid(i)]

def bell_number(n):
