import json
def task_func(data_list, json_file_name="mean_values.json"):
    if not data_list:
        mean_dict = {}
    else:
        # Transpose the data to group values by position
        transposed = list(itertools.zip_longest(*data_list, fillvalue=np.nan))
        mean_dict = {}
        for i, position_values in enumerate(transposed):
            # Calculate mean ignoring NaN values
            mean_value = np.nanmean(position_values)
            mean_dict[f'Position {i}'] = mean_value

    # Export to JSON file
    with open(json_file_name, 'w') as f:
        json.dump(mean_dict, f, indent=4)

    return mean_dict

