import json
import requests
import chardet

# Constants
API_URL = "http://api.example.com/data"

def task_func(url=API_URL, from_encoding=None, to_encoding="utf8"):
    try:
        response = requests.get(url, timeout=5)
        response.raise_for_status()
        content = response.content

        if not content:
            return {}

        if from_encoding is None:
            detected = chardet.detect(content)
            if not detected or not detected['encoding']:
                raise ValueError("Unable to detect encoding for non-empty content")
            from_encoding = detected['encoding']

        decoded_content = content.decode(from_encoding)
        re_encoded_content = decoded_content.encode(to_encoding).decode(to_encoding)

        return json.loads(re_encoded_content)
    except (requests.RequestException, json.JSONDecodeError, UnicodeDecodeError, ValueError) as e:
        if isinstance(e, ValueError) and "Unable to detect encoding" in str(e):
            raise
        return {}

import binascii
import hashlib
def task_func(input_string, verify_hash=None):
    if not isinstance(input_string, str):
        raise TypeError("Input must be a string")
    if verify_hash is not None and not isinstance(verify_hash, str):
        raise TypeError("verify_hash must be a string or None")

    hash_object = hashlib.sha256(input_string.encode('utf-8'))
    hex_dig = hash_object.hexdigest()

    if verify_hash is not None:
        return hex_dig, hex_dig == verify_hash
    else:
        return hex_dig, None

